<?php
 namespace WPAICG\ContentWriter\Ajax\Actions\Shared; use WPAICG\ContentWriter\Ajax\AIPKit_Content_Writer_Base_Ajax_Action; if (!defined('ABSPATH')) { exit; } function log_initial_request_logic(AIPKit_Content_Writer_Base_Ajax_Action $handler, array $request_data, string $request_type): void { if (!$handler->log_storage) { return; } $initial_request_details_for_log = [ 'title' => $request_data['content_title'] ?? '', 'keywords' => $request_data['content_keywords'] ?? null, ]; $conversation_uuid = $handler->ensure_content_writer_conversation_uuid( isset($request_data['conversation_uuid']) && !empty($request_data['conversation_uuid']) ? sanitize_text_field($request_data['conversation_uuid']) : '' ); $handler->log_storage->log_message(array_merge($handler->build_content_writer_log_base( $conversation_uuid, (string) ($request_data['provider'] ?? ''), (string) ($request_data['model'] ?? '') ), [ 'message_role' => 'user', 'message_content' => "Content Writer Request ({$request_type}): " . esc_html($request_data['content_title']), 'request_payload' => $initial_request_details_for_log ])); } 